svg.script:
var RUNS = {
  pk26L: { m:'k26', label:'K2.6 · longdoc · loop: 5,236 → 7,815 — escalates; false promise on turn 1', extra:['dk26L','lk26'] },
  pk3L:  { m:'k3',  label:'K3 · longdoc · loop: 5,666 → 1,025 — collapses; passes on turn 2', extra:['dk3L','lk3'] },
  pk3a:  { m:'k3',  label:'K3 · enumerate · generation: 3,038 → 1,188 → 155', extra:[] },
  pk3b:  { m:'k3',  label:'K3 · longdoc · generation: 4,546 → 2,336 → 1,389', extra:[] },
  pk3c:  { m:'k3',  label:'K3 · build · generation: 327 → 418 → 241 (idled — its one off-pattern run)', extra:[] },
  pk26a: { m:'k26', label:'K2.6 · enumerate · generation: 4,451 → 4,789 → 2,505', extra:[] },
  pk26b: { m:'k26', label:'K2.6 · build · generation: 3,047 → 1,863 → 1,770', extra:[] },
  pk26c: { m:'k26', label:'K2.6 · longdoc · generation: 8,365 → 361 → 1,056 (declared done on turn 2)', extra:[] }
};
var DEF = 'hover a line for exact per-turn values · click a legend chip to solo a model';
var solo = null, hovered = null;
function $(id){ return document.getElementById(id); }
function setEl(id, op, w){
  var el = $(id); if (!el) return;
  el.style.opacity = op;
  if (w && el.tagName === 'path') el.setAttribute('stroke-width', w);
}
function apply(){
  for (var id in RUNS){
    var r = RUNS[id], el = $(id);
    var baseOp = parseFloat(el.getAttribute('data-op'));
    var baseW = el.getAttribute('data-w');
    var op = baseOp, w = baseW;
    if (solo && r.m !== solo) op = 0.1;
    if (hovered){
      if (id === hovered){ op = 1; w = (parseFloat(baseW) + 0.9).toFixed(1); }
      else op = 0.1;
    }
    setEl(id, op, w);
    for (var k = 0; k < r.extra.length; k++) setEl(r.extra[k], op);
  }
  // one-shot bars follow the solo state only
  $('bk3').style.opacity  = (solo === 'k26') ? 0.15 : 1;
  $('bk26').style.opacity = (solo === 'k3') ? 0.15 : 1;
  $('ro').textContent = hovered ? RUNS[hovered].label : (solo ? ('solo: ' + (solo === 'k3' ? 'K3' : 'K2.6') + ' — click the chip again to clear') : DEF);
  $('ro').setAttribute('fill', hovered ? '#1b1b1a' : '#6b6b66');
  $('ro').setAttribute('font-weight', hovered ? '600' : '400');
  $('lr3').setAttribute('stroke-width', solo === 'k3' ? 2.2 : 1);
  $('lr26').setAttribute('stroke-width', solo === 'k26' ? 2.2 : 1);
}
var hits = document.getElementsByClassName('hit');
for (var i = 0; i < hits.length; i++)(function(h){
  h.addEventListener('pointerenter', function(){ hovered = h.getAttribute('data-run'); apply(); });
  h.addEventListener('pointerleave', function(){ hovered = null; apply(); });
})(hits[i]);
$('legk3').addEventListener('click', function(){ solo = (solo === 'k3') ? null : 'k3'; apply(); });
$('legk26').addEventListener('click', function(){ solo = (solo === 'k26') ? null : 'k26'; apply(); });
apply();
